#include <iostream>
using namespace std;

int main() {
    int x = 10;
    int &ref = x;
    ref = 20;
    cout << "x: " << x << endl; // Prints 20
    return 0;
}

#include <iostream>
using namespace std;

void print(int i) {
    cout << "Integer: " << i << endl;
}

void print(double d) {
    cout << "Double: " << d << endl;
}

int main() {
    print(5);
    print(5.5);
    return 0;
}

#include <iostream>
#include <string>
using namespace std;

void greet(string name, string msg = "Welcome") {
    cout << msg << ", " << name << endl;
}

int main() {
    greet("Alice");
    greet("Bob", "Hello");
    return 0;
}

