#include <iostream>
using namespace std;

int main() {
    bool isValid;
    cout << "Enter 1 for true, 0 for false: ";
    cin >> isValid;
    if (isValid) {
        cout << "Valid entry" << endl;
    } else {
        cout << "Invalid entry" << endl;
    }
    return 0;
}

#include <iostream>
using namespace std;

inline int square(int x) {
    return x * x;
}

int main() {
    cout << square(5) << endl;
    return 0;
}

#include <iostream>
using namespace std;

int main() {
    int *ptr = new int;
    *ptr = 100;
    cout << "Value: " << *ptr << endl;
    delete ptr;
    return 0;
}

#include <iostream>
using namespace std;

int x = 10; // Global

int main() {
    int x = 20; // Local
    cout << "Local x: " << x << endl;
    cout << "Global x: " << ::x << endl;
    return 0;
}
